import { CourseDetailDto, ModuleItemDto } from '../core/models/course.models';

/**
 * Helpers for Canvas-style sequential module navigation — the "Next / Previous"
 * flow a learner uses to move through a course's content one item at a time,
 * instead of browsing Pages/Quizzes lists directly.
 */

export interface ModuleNavTarget {
  link: unknown[];
  query: Record<string, unknown>;
}

/** Navigable items (Page/Quiz/Assignment, published) flattened in module then item order. */
export function navigableItems(course: CourseDetailDto): ModuleItemDto[] {
  return [...course.modules]
    .sort((a, b) => a.orderIndex - b.orderIndex)
    .flatMap(m => [...m.items].sort((a, b) => a.orderIndex - b.orderIndex))
    .filter(i => i.itemType !== 'SubHeader' && i.isPublished);
}

/** The item before (dir -1) or after (dir +1) the current one, or null at the ends. */
export function adjacentItem(
  items: ModuleItemDto[],
  currentItemId: number,
  dir: 1 | -1,
): ModuleItemDto | null {
  const idx = items.findIndex(i => i.id === currentItemId);
  if (idx === -1) return null;
  return items[idx + dir] ?? null;
}

/** Router target for a module item, mapped by its type. */
export function moduleItemRoute(courseId: number, item: ModuleItemDto): ModuleNavTarget {
  const query = { itemId: item.id, done: item.isCompleted };
  switch (item.itemType) {
    case 'Page':
      return { link: ['/courses', courseId, 'pages', item.pageId], query };
    case 'Quiz':
      return { link: ['/courses', courseId, 'quizzes', item.quizId], query };
    case 'Assignment':
      return { link: ['/courses', courseId, 'assignments', item.assignmentId], query };
    default:
      return { link: ['/courses', courseId], query: {} };
  }
}
